mapper.select:
SELECT d.diary_id, d.member_id, d.game_id, d.snapshot_team_code, d.is_verified, d.verified_at, g.game_date, g.game_type, IFNULL(s.short_name, s.name) AS stadiumName,
g.score_home AS scoreHome, g.score_away AS scoreAway, d.pred_score_home AS predScoreHome, d.pred_score_away AS predScoreAway,
/* 화면 뱃지 노출용: 응원팀(직관 팀) 스코어 기준 승패 판별 유지 */ CASE WHEN d.snapshot_team_code = g.home_team_code THEN CASE WHEN g.score_home > g.score_away THEN 'WIN' WHEN g.score_home < g.score_away THEN 'LOSE' ELSE 'DRAW' END WHEN d.snapshot_team_code = g.away_team_code THEN CASE WHEN g.score_away > g.score_home THEN 'WIN' WHEN g.score_away < g.score_home THEN 'LOSE' ELSE 'DRAW' END ELSE 'NONE' END AS gameResult FROM diaries d INNER JOIN games g ON d.game_id = g.game_id INNER JOIN stadiums s ON g.stadium_id = s.stadium_id WHERE d.member_id = #{memberId} AND d.is_verified = 1 AND g.status = 'FINISHED' AND d.status = 'COMPLETED' AND g.game_type IN ('REGULAR', 'POST', 'EXHIBITION') ORDER BY g.game_date DESC

SELECT *
FROM diaries
WHERE member_id = #{memberId}
  AND game_id = #{gameId}
  AND status != 'INVALID'
LIMIT 1

mapper.update:
UPDATE diaries
SET status     = #{status},
    updated_at = NOW()
WHERE diary_id = #{diaryId}
  AND member_id = #{memberId}

UPDATE diaries
SET view_count = IFNULL(view_count, 0) + 1
WHERE diary_id = #{diaryId}

UPDATE diaries
SET share_uuid = #{uuid}
WHERE diary_id = #{diaryId}

mapper.select:
SELECT COUNT(*)
FROM diaries d
         JOIN games g ON d.game_id = g.game_id
WHERE d.member_id = #{memberId}
  AND g.game_date = #{gameDate}
  AND d.status != 'INVALID'
